import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { DealFormService } from '../../services/deal-form.service';
import { Deal } from '../../models/deal-form.model';

@Component({
  selector: 'app-deal-list',
  templateUrl: './deal-list.component.html',
})
export class DealListComponent implements OnInit {
  deals: Deal[] = [];

  constructor(
    private svc: DealFormService,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.deals = this.svc.getDeals();
  }

  newDeal(): void {
    this.svc.clearDraft();
    this.router.navigate(['/deal/basic-info']);
  }

  formatDate(iso: string): string {
    return new Date(iso).toLocaleDateString('en-US', {
      day: '2-digit', month: 'short', year: 'numeric',
    });
  }

  formatAmount(deal: Deal): string {
    const amt = parseFloat(deal.depositDates.amount);
    if (isNaN(amt)) return '—';
    return `${deal.depositDates.currency} ${amt.toLocaleString('en-US', {
      minimumFractionDigits: 2, maximumFractionDigits: 2,
    })}`;
  }
}
<main class="main">

  <div class="list-header">
    <div>
      <h1 class="list-title">Money Market Deals</h1>
      <p class="list-subtitle">{{ deals.length }} deal{{ deals.length !== 1 ? 's' : '' }} in system</p>
    </div>
    <button type="button" class="btn btn-primary" (click)="newDeal()">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
        <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
      </svg>
      New Deal
    </button>
  </div>

  <!-- Empty state -->
  <div *ngIf="deals.length === 0" class="empty-state">
    <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" style="color:var(--text-placeholder)">
      <rect x="2" y="7" width="20" height="14" rx="2"/>
      <path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/>
    </svg>
    <p>No deals yet. Create your first money market deal.</p>
    <button type="button" class="btn btn-primary" (click)="newDeal()">Create Deal</button>
  </div>

  <!-- Deal table -->
  <div *ngIf="deals.length > 0" class="form-card" style="overflow:visible">
    <table class="deal-table">
      <thead>
        <tr>
          <th>Deal ID</th>
          <th>Date</th>
          <th>Counterparty</th>
          <th>Instrument</th>
          <th>Amount</th>
          <th>Type</th>
          <th>Status</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let deal of deals">
          <td class="deal-id">{{ deal.id }}</td>
          <td>{{ formatDate(deal.createdAt) }}</td>
          <td>{{ deal.basicInfo.counterparty }}</td>
          <td>{{ deal.basicInfo.instrument }}</td>
          <td class="amount-cell">{{ formatAmount(deal) }}</td>
          <td>{{ deal.basicInfo.dealType }}</td>
          <td>
            <span class="status-badge" [class.on-hold]="deal.status === 'On Hold'" [class.released]="deal.status === 'Released'">
              {{ deal.status }}
            </span>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

</main>
